    };
    
    $sql = "SELECT 
                DATE_FORMAT(created_at, :date_format) as period,
                COUNT(*) as count,
                SUM(amount) as total_amount,
                AVG(amount) as avg_amount
            FROM reports 
            WHERE 1=1";
    
    $params = [':date_format' => $dateFormat];
    
